  //       },

  //       {
  //         path: "/friends",
  //         element: <Friends></Friends>,
  //       },
  //       {
  //         path: "/:id",
  //         element: (
  //           <Chat
  //             token={token}
  //             sendMessageHandler={sendMessageHandler}
  //             userId={userId}
  //           ></Chat>
  //         ),
  //       },
  //     ],
  //   },
  //   {
  //     path: "/",
  //     loader: () => {
  //       if (isAuth && !isLoading) return redirect("/");
  //       return null;
  //     },
  //     element: (
  //       <Layout>
  //         <Outlet></Outlet>
  //       </Layout>
  //     ),
  //     children: [
  //       {
  //         path: "/login",
  //         element: <Login loginHandler={loginHandler} />,
  //       },
  //       {
  //         path: "/register",
  //         element: (
  //           <Register
  //             registerHandler={registerHandler}
  //             loginHandler={loginHandler}
  //           />
  //         ),
  //       },
  //     ],
  //   },
  // ]);

  if (isLoading) {
    return;
  }

  return (
    <AppContainer
      isAuth={isAuth}
      token={token}
      userId={userId}
      logoutHandler={logoutHandler}
      loginHandler={loginHandler}
      registerHandler={registerHandler}
    ></AppContainer>
  );
}

export default App;
